function solve(n: number, edges: number[][], label: string): number {
    // Build adjacency list
    const adj = new Array(n).fill(0).map(() => new Array<number>());
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    // Memoization to store the longest palindrome length for a given node and visited set
    const memo = new Map<string, number>();

    // Helper function to perform DFS
    function dfs(node: number, visited: number[]): number {
        const key = node + "," + visited.join(",");
        if (memo.has(key)) return memo.get(key) as number;

        // Initialize the maximum palindrome length for this node
        let maxLen = 1; // At least the node itself is a palindrome of length 1

        // Check all neighbors
        for (const neighbor of adj[node]) {
            if (!visited.includes(neighbor)) {
                // Mark the neighbor as visited
                const newVisited = [...visited, neighbor];
                // Get the palindrome length from the neighbor
                const len = dfs(neighbor, newVisited);
                // Update the maximum length
                maxLen = Math.max(maxLen, len);
            }
        }

        // Store the result in memoization
        memo.set(key, maxLen);
        return maxLen;
    }

    // Try all starting nodes
    let result = 0;
    for (let i = 0; i < n; i++) {
        const visited = [i];
        const len = dfs(i, visited);
        result = Math.max(result, len);
    }

    return result;
}

